import java.util.*;class A{static int L,H;static String[][]G=new String[20][20];static Map<String,Integer>M=new HashMap<>();static Scanner s=new Scanner(System.in);static long R(){int n=s.nextInt();s.nextLine();var v=new String[n];for(int i=0;i<n;i++)v[i]=s.nextLine();long r=0;for(int i=0;i<n/H;i++){var k="";for(int j=0;j<H;j++){if(j>0)k+="\n";k+=v[i*H+j];}r=r*20+M.get(k);}return r;}public static void main(String[]a){L=s.nextInt();H=s.nextInt();s.nextLine();for(int i=0;i<H;i++){var r=s.nextLine();for(int j=0;j<20;j++)G[j][i]=r.substring(j*L,j*L+L);}for(int i=0;i<20;i++){var k="";for(int j=0;j<H;j++){if(j>0)k+="\n";k+=G[i][j];}M.put(k,i);}long x=R(),y=R();var o=s.nextLine();long r=o.equals("+")?x+y:o.equals("-")?x-y:o.equals("*")?x*y:x/y;var d=new ArrayList<Integer>();if(r==0)d.add(0);else while(r>0){d.add(0,(int)(r%20));r/=20;}for(int v:d)for(int j=0;j<H;j++)System.out.println(G[v][j]);}}